import type {
  DataDrivenPropertyValueSpecification,
  ExpressionSpecification,
} from '@maplibre/maplibre-gl-style-spec';

import { addOutlineSize } from './add-outline-size.js';

//#region FIXED PARAMETERS
const MAP_MAX_ZOOM_LEVEL = 22;
const MAP_MIN_ZOOM_LEVEL = 0;
const EQUATOR_METERS_BY_PIXEL_MAX_ZOOM_LEVEL_RATIO = 0.019;
//#endregion

//#region FINE-TUNING PARAMETERS
const shrinkFactor = 4;
const gainAtMaxZoomLevel = 10000;
//#endregion

/**
 * Expression to scale latitude in Mercator projection.
 */
const mercatorLatitudeScalingFactor: ExpressionSpecification = [
  'cos',
  ['*', ['get', '__lat'], ['/', Math.PI, 180]],
];

/**
 * Expression to calculate the radius size at the minimum zoom level
 */
const minZoomLevelCalculation: ExpressionSpecification = [
  '/',
  ['get', '__radius'],
  shrinkFactor,
];

/**
 * Expression to calculate the radius size at the maximum zoom level
 */
const maxZoomLevelCalculation: ExpressionSpecification = [
  '/',
  [
    '/',
    ['*', ['get', '__radius'], gainAtMaxZoomLevel],
    EQUATOR_METERS_BY_PIXEL_MAX_ZOOM_LEVEL_RATIO,
  ],
  mercatorLatitudeScalingFactor,
];

/**
 * Builds the circle stick to distance expression.
 * It creates an exponential interpolation between the radius size at the minimum zoom level and the maximum zoom level
 * to generate the stick to distance effect.
 */
export const buildCircleStickToDistanceExpression =
  (): DataDrivenPropertyValueSpecification<number> => {
    return [
      'interpolate',
      ['exponential', 2],
      ['zoom'],
      MAP_MIN_ZOOM_LEVEL,
      minZoomLevelCalculation,
      MAP_MAX_ZOOM_LEVEL,
      maxZoomLevelCalculation,
    ];
  };

/**
 * Builds the outline stick to distance expression.
 * It creates an exponential interpolation between the outline radius size at the minimum zoom level and the maximum
 * zoom level to generate the stick to distance effect.
 */
export const buildOutlineStickToDistanceExpression =
  (): DataDrivenPropertyValueSpecification<number> => {
    return [
      'interpolate',
      ['exponential', 2],
      ['zoom'],
      MAP_MIN_ZOOM_LEVEL,
      addOutlineSize(minZoomLevelCalculation),
      MAP_MAX_ZOOM_LEVEL,
      addOutlineSize(maxZoomLevelCalculation),
    ];
  };
